#include "bh1750_sensor.h"
#include <Wire.h>
#include <BH1750.h>
#include "config.h"

static BH1750 _lightMeter(0x23);
static bool _bh1750Ready = false;
static float _currentLux = 0;

void bh1750_setup() {
    Wire.begin(21, 22);
    if (_lightMeter.begin(BH1750::CONTINUOUS_HIGH_RES_MODE)) {
        _bh1750Ready = true;
        Serial.println("[bh1750] Light sensor ready");
    } else {
        Serial.println("[bh1750] FAILED");
    }
}

void bh1750_loop() {
    if (!_bh1750Ready) return;
    if (_lightMeter.measurementReady()) {
        _currentLux = _lightMeter.readLightLevel();
        // Auto-adjust sensitivity for very bright/dark conditions
        if (_currentLux < 0) {
            Serial.println("[bh1750] Error reading");
        } else if (_currentLux > 40000) {
            _lightMeter.configure(BH1750::CONTINUOUS_HIGH_RES_MODE_2);
        } else {
            _lightMeter.configure(BH1750::CONTINUOUS_HIGH_RES_MODE);
        }
    }
}

float bh1750_lux() { return _currentLux; }
bool bh1750_ready() { return _bh1750Ready; }
